// Some portions generated by Co-Pilot
import { describe, it, expect, afterEach } from "vitest";
import { render, screen, cleanup } from "@testing-library/react";
import DownloadCounter from "../index";

describe("DownloadCounter", () => {
  afterEach(() => {
    cleanup();
  });

  it("renders the download counter section", () => {
    const { container } = render(<DownloadCounter total={500000000} />);
    expect(container.firstChild).toBeInTheDocument();
  });

  it("renders the title text", () => {
    render(<DownloadCounter total={500000000} />);
    // useTranslations mock returns "Text"
    expect(screen.getAllByText("Text").length).toBeGreaterThan(0);
  });

  it("renders the GitHub stats link", () => {
    render(<DownloadCounter total={500000000} />);
    const links = screen.getAllByRole("link");
    const statsLink = links.find(
      (link) => link.getAttribute("href") === "https://adoptium.net/stats/download"
    );
    expect(statsLink).toBeDefined();
  });

  it("starts counter at 0 before animation", () => {
    render(<DownloadCounter total={500000000} />);
    // Counter starts at 0 before intersection observer triggers
    const zeros = screen.getAllByText("0");
    expect(zeros.length).toBeGreaterThan(0);
  });

  it("handles total of 0", () => {
    render(<DownloadCounter total={0} />);
    const zeros = screen.getAllByText("0");
    expect(zeros.length).toBeGreaterThan(0);
  });
});
